#!/usr/bin/env node
// Build an OKF v0.1 bundle from README.md.
//
// The repository root is an Awesome list (README.md) and therefore cannot itself
// be a conformant bundle, because OKF requires every non-reserved .md file to
// carry frontmatter with a non-empty `type` (which would break README/awesome-lint).
//
// Instead we mirror the list as a self-contained, conformant bundle under bundle/:
// one concept file per list entry, plus the reserved index.md and log.md. This
// script regenerates the concepts and index, validates conformance, and preserves
// log.md (append-only history). Run it whenever README.md changes.
//
// Usage: node scripts/build-okf-bundle.mjs

import {
  readFileSync, writeFileSync, mkdirSync, rmSync,
  existsSync, readdirSync, statSync,
} from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');
const README = join(ROOT, 'README.md');
const BUNDLE = join(ROOT, 'bundle');
const BUILD_DATE = '2026-06-23T00:00:00Z';

// Sections of README.md that map to OKF concept types. Sections not listed here
// (Contents, OKF at a Glance, Contributing) are skipped.
const TYPE_BY_SECTION = {
  'Specification': 'Specification',
  'Official Tools & Reference Implementations': 'Reference Implementation',
  'Sample Bundles': 'Sample Bundle',
  'Community Tools': 'Tool',
  'Articles & Guides': 'Article',
  'Background & Origins': 'Origin',
  'Built on the LLM-Wiki Pattern': 'Implementation',
  'Related Formats & Concepts': 'Related Concept',
  'Community': 'Community',
};

const slug = (s) =>
  s.toLowerCase().replace(/`/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');

// JSON.stringify produces a valid YAML double-quoted scalar (escapes " and \).
const y = (v) => JSON.stringify(v);

function parseReadme() {
  const lines = readFileSync(README, 'utf8').split('\n');
  const itemRe = /^- \[([^\]]+)\]\(([^)]+)\) - (.+)$/;
  const sections = [];
  let cur = null;
  for (const line of lines) {
    const h = line.match(/^## (.+)$/);
    if (h) { cur = { title: h[1].trim(), items: [] }; sections.push(cur); continue; }
    if (!cur) continue;
    const m = line.match(itemRe);
    if (m) cur.items.push({ name: m[1].trim(), url: m[2].trim(), desc: m[3].trim() });
  }
  return sections.filter((s) => TYPE_BY_SECTION[s.title] && s.items.length);
}

function build() {
  // Clear generated concept directories, but preserve log.md (append-only history).
  if (existsSync(BUNDLE)) {
    for (const e of readdirSync(BUNDLE)) {
      if (e === 'log.md') continue;
      rmSync(join(BUNDLE, e), { recursive: true, force: true });
    }
  }
  mkdirSync(BUNDLE, { recursive: true });

  const sections = parseReadme();
  const index = [
    '# Awesome OKF Bundle',
    '',
    'This bundle is an OKF v0.1 mirror of the [Awesome OKF](https://github.com/linyiru/awesome-okf) list. Each entry is a concept file with frontmatter. Generated by `scripts/build-okf-bundle.mjs`.',
    '',
  ];
  let count = 0;

  for (const sec of sections) {
    const sslug = slug(sec.title);
    const type = TYPE_BY_SECTION[sec.title];
    mkdirSync(join(BUNDLE, sslug), { recursive: true });
    index.push(`## ${sec.title}`, '');
    for (const it of sec.items) {
      const islug = slug(it.name);
      const concept = [
        '---',
        `type: ${y(type)}`,
        `title: ${y(it.name)}`,
        `description: ${y(it.desc)}`,
        `resource: ${y(it.url)}`,
        `tags: [${y(sslug)}]`,
        `timestamp: ${BUILD_DATE}`,
        '---',
        '',
        `# ${it.name}`,
        '',
        it.desc,
        '',
        `- Resource: <${it.url}>`,
        '- See also: [bundle index](../index.md)',
        '',
      ].join('\n');
      writeFileSync(join(BUNDLE, sslug, `${islug}.md`), concept);
      index.push(`- [${it.name}](${sslug}/${islug}.md) - ${it.desc}`);
      count++;
    }
    index.push('');
  }

  writeFileSync(join(BUNDLE, 'index.md'), index.join('\n').replace(/\n{3,}/g, '\n\n').trimEnd() + '\n');

  if (!existsSync(join(BUNDLE, 'log.md'))) {
    writeFileSync(
      join(BUNDLE, 'log.md'),
      `# Log\n\n- ${BUILD_DATE} — Initial bundle generated from README.md (${count} concepts).\n`,
    );
  }
  return count;
}

function validate() {
  let ok = true;
  let total = 0;
  const walk = (dir) => {
    for (const e of readdirSync(dir)) {
      const p = join(dir, e);
      if (statSync(p).isDirectory()) { walk(p); continue; }
      if (!e.endsWith('.md')) continue;
      if (e === 'index.md' || e === 'log.md') continue; // reserved filenames
      total++;
      const txt = readFileSync(p, 'utf8');
      const m = txt.match(/^---\n([\s\S]*?)\n---/);
      if (!m) { console.error(`  ✗ ${p}: missing frontmatter`); ok = false; continue; }
      if (!/\btype:\s*\S/.test(m[1])) { console.error(`  ✗ ${p}: missing non-empty type`); ok = false; }
    }
  };
  walk(BUNDLE);
  console.log(`Validated ${total} concept files.`);
  return ok;
}

const n = build();
console.log(`Generated ${n} concepts into bundle/.`);
if (!validate()) {
  console.error('Bundle is NOT conformant to OKF v0.1.');
  process.exit(1);
}
console.log('Bundle conforms to OKF v0.1.');
